import { test, expect } from '@playwright/test';

test('Amazon.sg search for laptop and verify results', async ({ page }) => {
  // Navigate to Amazon.sg
  await page.goto('https://www.amazon.sg/');

  // Find the search box in the header/navigation area
  const searchBox = page.locator('input[type="text"][placeholder="Search Amazon.sg"]');
  await expect(searchBox).toBeVisible();

  // Click on the search input field
  await searchBox.click();

  // Type "laptop" in the search box
  await searchBox.fill('laptop');

  // Press Enter to search
  await searchBox.press('Enter');

  // Wait for product results to load
  const productResults = page.locator('div.s-main-slot div[data-component-type="s-search-result"]');
  await expect(productResults.first()).toBeVisible({ timeout: 10000 });

  // Verify that product listing page is displayed with multiple items
  const itemCount = await productResults.count();
  expect(itemCount).toBeGreaterThan(1);
});
